#include <iostream>
#include <iomanip>

int main()
{
    int a, b;
    std::cin >> a >> b;

    std::cout << "Integer division: " << a / b << '\n';
    std::cout << std::fixed << std::setprecision(1);
    std::cout << "Float division: " << static_cast<double>(a) / b << '\n';
    std::cout << "Double a: " << static_cast<double>(a) << '\n';

    return 0;
}

