solution_code:
#include <iostream>

auto clamp_value(int value, int lo, int hi)
{
    if (value < lo)
        return lo;
    if (value > hi)
        return hi;
    return value;
}

int main()
{
    int value, lo, hi;
    std::cin >> value >> lo >> hi;
    std::cout << "Clamped: " << clamp_value(value, lo, hi) << '\n';
    return 0;
}
